import React, { useState, useEffect, useRef } from 'react';
import { useSettings } from '../context/SettingsContext';
import { Link, useLocation } from 'react-router-dom';

const Navigation = () => {
  const [isOpen, setIsOpen] = useState(false);
  const location = useLocation();
  const navRef = useRef(null);
  const { muteAudio, setMuteAudio, psxDither, setPsxDither } = useSettings();
  const openSoundRef = useRef(null);
  const hoverSoundRef = useRef(null);

  // Close menu when route changes
  useEffect(() => {
    setIsOpen(false);
  }, [location]);

  // Body scroll lock & initial focus on open
  useEffect(() => {
    document.body.style.overflow = isOpen ? 'hidden' : '';
    if (isOpen && navRef.current) {
      // Focus first link after opening for accessibility
      setTimeout(() => {
        const firstLink = navRef.current.querySelector('a');
        firstLink && firstLink.focus();
      }, 0);
    }
    return () => { document.body.style.overflow = ''; };
  }, [isOpen]);

  const play = (ref, volume = 0.15) => {
    if (!ref.current || muteAudio) return;
    try { ref.current.currentTime = 0; ref.current.volume = volume; ref.current.play(); } catch {}
  };
  const toggleMenu = () => {
    play(openSoundRef, 0.18);
    setIsOpen(o => !o);
  };

  // Keyboard: ESC to close, basic focus trap
  useEffect(() => {
    const handleKey = (e) => {
      if (!isOpen) return;
      if (e.key === 'Escape') {
        setIsOpen(false);
      } else if (e.key === 'Tab' && navRef.current) {
        const focusables = navRef.current.querySelectorAll('a');
        if (!focusables.length) return;
        const first = focusables[0];
        const last = focusables[focusables.length - 1];
        if (e.shiftKey && document.activeElement === first) {
          e.preventDefault();
          last.focus();
        } else if (!e.shiftKey && document.activeElement === last) {
          e.preventDefault();
          first.focus();
        }
      } else if (e.key === 'Enter' || e.key === ' ') {
        // Allow activating the hamburger via keyboard when focused
        if (document.activeElement?.classList.contains('hamburger-menu')) {
          e.preventDefault();
          toggleMenu();
        }
      }
    };
    document.addEventListener('keydown', handleKey);
    return () => document.removeEventListener('keydown', handleKey);
  }, [isOpen]);

  return (
    <>
      <div
        className={`hamburger-menu ${isOpen ? 'open' : ''}`}
        onClick={toggleMenu}
        role="button"
        aria-label="Navigation menu"
        aria-expanded={isOpen}
        aria-controls="main-navigation"
        tabIndex={0}
      >
        <div className="hamburger-line"></div>
        <div className="hamburger-line"></div>
        <div className="hamburger-line"></div>
      </div>
      
      <nav
        id="main-navigation"
        ref={navRef}
        className={`nav-menu ${isOpen ? 'open' : ''}`}
        aria-hidden={!isOpen}
      >
  <ul onMouseOver={(e) => { if (e.target.closest('a')) play(hoverSoundRef, 0.08); }}>
          <li>
            <Link to="/">Home</Link>
          </li>
          <li>
            <Link to="/contact">Contact</Link>
          </li>
          <li className="nav-divider" aria-hidden="true" />
          <li className="nav-toggle">
            <label>
              <input
                type="checkbox"
                checked={muteAudio}
                onChange={(e) => setMuteAudio(e.target.checked)}
              />
              Mute audio
            </label>
          </li>
          <li className="nav-toggle">
            <label>
              <input
                type="checkbox"
                checked={psxDither}
                onChange={(e) => setPsxDither(e.target.checked)}
              />
              PSX dither mode
            </label>
          </li>
        </ul>
      </nav>

      <div 
        className={`menu-overlay ${isOpen ? 'visible' : ''}`}
        onClick={toggleMenu}
      />

      {/* UI blip sounds (respect mute) */}
      <audio ref={openSoundRef} preload="auto">
        <source src={process.env.PUBLIC_URL + '/audio/ui-open.mp3'} type="audio/mpeg" />
      </audio>
      <audio ref={hoverSoundRef} preload="auto">
        <source src={process.env.PUBLIC_URL + '/audio/ui-hover.mp3'} type="audio/mpeg" />
      </audio>
    </>
  );
};

export default Navigation;
